CREATE TABLE IF NOT EXISTS `{prefix}_forum_cats` ( `id` int(11) NOT NULL AUTO_INCREMENT, `parent_id` int(11) DEFAULT '0', `name` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `description` varchar(500) DEFAULT '', `icon` varchar(100) DEFAULT 'fa-folder', `posi` int(11) DEFAULT '0', `topic_count` int(11) DEFAULT '0', `post_count` int(11) DEFAULT '0', `last_topic_id` int(11) DEFAULT '0', `last_post_id` int(11) DEFAULT '0', `permissions` varchar(100) DEFAULT 'all', PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `parent_id` (`parent_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_topics` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL, `title` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `user_id` int(11) NOT NULL, `views` int(11) DEFAULT '0', `replies` int(11) DEFAULT '0', `is_pinned` tinyint(1) DEFAULT '0', `is_locked` tinyint(1) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `last_bump_date` datetime DEFAULT NULL, `last_post_id` int(11) DEFAULT '0', `last_user_id` int(11) DEFAULT '0', `last_post_date` datetime DEFAULT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `cat_id` (`cat_id`), KEY `user_id` (`user_id`), KEY `last_post_date` (`last_post_date`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_posts` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `text` mediumtext NOT NULL, `likes` int(11) DEFAULT '0', `dislikes` int(11) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `is_approved` tinyint(1) NOT NULL DEFAULT '1', `ip` varchar(45) DEFAULT '', `date` datetime NOT NULL, `updated_at` datetime DEFAULT NULL, PRIMARY KEY (`id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_notifs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `from_user` int(11) NOT NULL, `type` varchar(50) NOT NULL, `topic_id` int(11) NOT NULL, `post_id` int(11) DEFAULT '0', `is_read` tinyint(1) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `user_id` (`user_id`), KEY `is_read` (`is_read`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_ranks` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(100) NOT NULL, `points` int(11) NOT NULL DEFAULT '0', `color` varchar(20) DEFAULT '#001f3f', `icon` varchar(100) DEFAULT 'fa-user', `badge_text` varchar(50) DEFAULT '', PRIMARY KEY (`id`), KEY `points` (`points`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_subs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_likes` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `type` enum('like','dislike') NOT NULL DEFAULT 'like', `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_post` (`user_id`,`post_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_readlog` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `last_read_post` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_edit_history` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `editor_id` int(11) NOT NULL, `old_text` mediumtext NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_pm` ( `id` int(11) NOT NULL AUTO_INCREMENT, `from_user` int(11) NOT NULL, `to_user` int(11) NOT NULL, `title` varchar(255) NOT NULL, `text` text NOT NULL, `is_read` tinyint(1) DEFAULT '0', `del_sender` tinyint(1) DEFAULT '0', `del_receiver` tinyint(1) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `to_user` (`to_user`), KEY `from_user` (`from_user`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_logs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `mod_id` int(11) NOT NULL, `action` varchar(255) NOT NULL, `target_type` varchar(30) DEFAULT 'topic', `topic_id` int(11) DEFAULT '0', `post_id` int(11) DEFAULT '0', `date` datetime NOT NULL, `ip` varchar(45) NOT NULL, PRIMARY KEY (`id`), KEY `mod_id` (`mod_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_settings` ( `name` varchar(100) NOT NULL, `value` text NOT NULL, PRIMARY KEY (`name`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_banned_words` ( `id` int(11) NOT NULL AUTO_INCREMENT, `word` varchar(255) NOT NULL, `replacement` varchar(255) DEFAULT '***', PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_attachments` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `filename` varchar(255) NOT NULL, `original_name` varchar(255) NOT NULL, `filesize` int(11) DEFAULT '0', `filetype` varchar(100) DEFAULT '', `is_image` tinyint(1) DEFAULT '0', `downloads` int(11) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE `{prefix}_users` ADD COLUMN IF NOT EXISTS `forum_points` INT(11) DEFAULT '0'; ALTER TABLE `{prefix}_users` ADD COLUMN IF NOT EXISTS `forum_rank_id` INT(11) DEFAULT '0'; ALTER TABLE `{prefix}_users` ADD COLUMN IF NOT EXISTS `forum_post_count` INT(11) DEFAULT '0'; ALTER TABLE `{prefix}_forum_posts` ADD COLUMN IF NOT EXISTS `dislikes` INT(11) DEFAULT '0'; ALTER TABLE `{prefix}_forum_likes` ADD COLUMN IF NOT EXISTS `type` ENUM('like','dislike') NOT NULL DEFAULT 'like';
INSERT IGNORE INTO `{prefix}_forum_settings` (`name`, `value`) VALUES ('posts_per_page', '20'), ('topics_per_page', '25'), ('allow_guests_view', '1'), ('min_post_length', '10'), ('max_post_length', '10000'), ('allow_attachments', '1'), ('max_attachment_size', '5242880'), ('allowed_filetypes', 'jpg,jpeg,png,gif,webp,pdf,zip,rar,doc,docx'), ('flood_time', '30'), ('points_new_topic', '10'), ('points_new_reply', '2'), ('points_received_like', '5'), ('approval_threshold', '0'), ('bump_cooldown_hours', '24');
INSERT IGNORE INTO `{prefix}_forum_ranks` (`title`, `points`, `color`, `icon`, `badge_text`) VALUES ('Yeni Üye', 0, '#888888', 'fa-user', 'Yeni'), ('Aktif Üye', 100, '#27ae60', 'fa-user-plus', 'Aktif'), ('Uzman', 500, '#2980b9', 'fa-star', 'Uzman'), ('Efsane Üye', 2000, '#8e44ad', 'fa-trophy', 'Efsane'), ('Moderatör', 9999, '#e74c3c', 'fa-shield', 'Mod');
INSERT IGNORE INTO `{prefix}_admin_sections` (`name`, `title`, `descr`, `icon`, `allow_groups`) VALUES ('forum', 'Forum Yönetimi', 'DLE Native Forum v3.5', 'forum.png', '1');

