DROP TABLE IF EXISTS `{prefix}_forum_posts`;
DROP TABLE IF EXISTS `{prefix}_forum_topics`;
DROP TABLE IF EXISTS `{prefix}_forum_cats`;

-- Menü
DELETE FROM `{prefix}_admin_sections` 
WHERE name='forum';

operation.replacecode:
if ($do == "forum") {
    $dle_module = "forum"; 
    $allow_active_news = false; // BU SATIRI EKLE: Makalelerin yüklenmesini kökten keser.
    include_once (DLEPlugins::Check(ENGINE_DIR . '/forum/init.php'));
}

} elseif ($_POST['action'] == "forum") {
    // 1. GÜVENLİK: CSRF Token Kontrolü
    if (!isset($_POST['user_hash']) || $_POST['user_hash'] != $dle_login_hash) {
        die("error");
    }

    // 2. Yetki ve Flood Koruması
    if (!$is_logged) {
        $author = $db->safesql($_IP);
        $db->query("SELECT id FROM " . PREFIX . "_complaint WHERE `from`='{$author}'");
        if ($db->num_rows() > 2) {
            echo $lang['error_complaint_1']; // Çok fazla şikayet
            die();
        }
    } else {
        $author = $db->safesql($member_id['name']);
    }

    // GÜVENLİK: ID'yi kesinlikle tam sayıya çeviriyoruz
    $id = intval($id); 
    if (!$id) die("error");

    $text = trim($_POST['text'] ?? '');
    if (empty($text)) {
        echo $lang['error_complaint_4']; // Boş mesaj
        die();
    }

    // 3. Limite Takılma Kontrolü
    $row = $db->super_query("SELECT COUNT(*) as count FROM " . PREFIX . "_complaint WHERE text LIKE '[FORUM]%' AND `from`='{$author}'");
    if ($row['count'] >= $config['max_complaints']) {
        echo $lang['error_complaint_5'];
        die();
    }

    // 4. Veritabanı Kontrolü
    $post = $db->super_query("SELECT p.topic_id, t.title FROM " . PREFIX . "_forum_posts p LEFT JOIN " . PREFIX . "_forum_topics t ON t.id = p.topic_id WHERE p.id = '{$id}'");

    if (!$post) die("error"); // Post bulunamadı

    // -------------------------------------------------------------------------------------------------------------
    // 5. VERİ HAZIRLAMA (XSS VE LOGIC DÜZELTMELERİ BURADA)
    // -------------------------------------------------------------------------------------------------------------

    // XSS KORUMASI: Tüm metinleri HTML etiketlerinden arındırıyoruz (Admin panelinde çalışmasını engellemek için)
    $safe_text = htmlspecialchars($text, ENT_QUOTES, 'UTF-8');
    $safe_topic_title = htmlspecialchars($post['title'], ENT_QUOTES, 'UTF-8');

    $safe_topic_id = intval($post['topic_id']);
    $raw_topic_link = $config['http_home_url'] . 'index.php?do=forum&action=topic&id=' . $safe_topic_id;

    // Metni güvenli haliyle birleştiriyoruz
    $raw_complaint_text = "[FORUM] Mesaj ID: #{$id} | Konu: {$safe_topic_title} | Link: {$raw_topic_link} | Neden: {$safe_text}";

    // Ve bilgileri veritabanına yazmadan ANCAK BURADA tek bir seferde SQL korumasına alıyoruz.
    $complaint_text = $db->safesql($raw_complaint_text);

    // LOGIC DÜZELTMESİ: news_id kısmına 0 veriyoruz! 
    // Aksi takdirde DLE admin paneli bu ID'yi bir haber (news) sanıp kırık/yanlış linke yönlendirir.
    $db->query("INSERT INTO " . PREFIX . "_complaint (`news_id`, `from`, `text`, `date`) VALUES ('0', '{$author}', '{$complaint_text}', '{$_TIME}')");

    // 6. MAIL BİLDİRİMİ (İÇERİK DÜZELTMESİ)
    if ($config['allow_complaint_mail']) {
        // Standart boş şablon yerine, adminin mailinden direkt okuyabileceği detaylı mesaj oluşturuyoruz.
        $mail_message = "Sitenizde yeni bir Forum Şikayeti yapıldı:\n\n" . $raw_complaint_text . "\n\nLütfen Yönetim Paneline girerek durumu inceleyiniz.";
        $mail->send($config['admin_mail'], "Yeni Forum Şikayeti: " . $safe_topic_title, $mail_message);
    }

    echo "ok"; // Başarılı yanıt
    die();
